
/*
  # ПДД Экзамен — Создание таблиц и наполнение вопросами

  1. Новые таблицы
    - `questions` — банк вопросов ПДД
      - id (uuid, primary key)
      - number (int, порядковый номер)
      - text (text, текст вопроса)
      - options (jsonb, массив вариантов ответа)
      - correct_index (int, индекс правильного ответа 0-3)
      - category (text, категория вопроса)
      - explanation (text, пояснение к ответу)
    - `exam_results` — результаты экзаменов
      - id (uuid, primary key)
      - score (int, количество правильных ответов)
      - total (int, всего вопросов)
      - passed (bool, сдал/не сдал)
      - time_spent (int, секунды)
      - mistakes (int, ошибок)
      - created_at (timestamp)

  2. Безопасность
    - RLS включён на обеих таблицах
    - Вопросы доступны всем (публичные данные)
    - Результаты — анонимная запись и чтение

  3. Данные
    - Предзаполнено 40 вопросов по ПДД РФ
*/

CREATE TABLE IF NOT EXISTS questions (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  number int NOT NULL,
  text text NOT NULL,
  options jsonb NOT NULL,
  correct_index int NOT NULL CHECK (correct_index >= 0 AND correct_index <= 3),
  category text NOT NULL DEFAULT 'Общие',
  explanation text NOT NULL DEFAULT '',
  created_at timestamptz DEFAULT now()
);

CREATE TABLE IF NOT EXISTS exam_results (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  score int NOT NULL DEFAULT 0,
  total int NOT NULL DEFAULT 20,
  passed boolean NOT NULL DEFAULT false,
  time_spent int NOT NULL DEFAULT 0,
  mistakes int NOT NULL DEFAULT 0,
  created_at timestamptz DEFAULT now()
);

ALTER TABLE questions ENABLE ROW LEVEL SECURITY;
ALTER TABLE exam_results ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Questions are publicly readable"
  ON questions FOR SELECT
  TO anon, authenticated
  USING (true);

CREATE POLICY "Anyone can insert exam results"
  ON exam_results FOR INSERT
  TO anon, authenticated
  WITH CHECK (true);

CREATE POLICY "Anyone can read exam results"
  ON exam_results FOR SELECT
  TO anon, authenticated
  USING (true);

INSERT INTO questions (number, text, options, correct_index, category, explanation) VALUES
(1, 'Что должен сделать водитель, если при движении автомобиль начало заносить?', '["Нажать на педаль тормоза", "Повернуть руль в сторону заноса и плавно снизить скорость", "Повернуть руль в противоположную сторону заноса", "Резко нажать на газ"]', 1, 'Управление ТС', 'При заносе необходимо повернуть руль в сторону заноса и плавно снизить скорость, избегая резких движений.'),

(2, 'Какова максимально допустимая скорость движения в жилой зоне?', '["10 км/ч", "20 км/ч", "30 км/ч", "40 км/ч"]', 1, 'Скоростной режим', 'В жилых зонах и на дворовых территориях скорость не должна превышать 20 км/ч.'),

(3, 'Какое максимальное количество ошибок допускается при сдаче экзамена по ПДД?', '["0", "1", "2", "3"]', 2, 'Общие', 'Допускается не более 2 ошибок при сдаче теоретического экзамена по ПДД.'),

(4, 'С какого возраста разрешается управление мотоциклом категории A?', '["16 лет", "17 лет", "18 лет", "21 год"]', 2, 'Общие', 'Управление мотоциклами категории A разрешается с 18 лет.'),

(5, 'Что означает мигающий зелёный сигнал светофора?', '["Разрешает движение, но предупреждает об окончании зелёного сигнала", "Запрещает движение", "Разрешает движение в любом направлении", "Требует остановки"]', 0, 'Светофоры', 'Мигающий зелёный сигнал разрешает движение, информируя водителя о скором переключении на жёлтый сигнал.'),

(6, 'Какова максимально допустимая скорость на автомагистрали для легковых автомобилей?', '["90 км/ч", "100 км/ч", "110 км/ч", "130 км/ч"]', 3, 'Скоростной режим', 'На автомагистралях максимальная допустимая скорость для легковых автомобилей составляет 130 км/ч.'),

(7, 'При движении по дороге с несколькими полосами в одном направлении, какую полосу должен занимать водитель?', '["Левую", "Среднюю", "Крайнюю правую, кроме случаев обгона или объезда", "Любую по желанию"]', 2, 'Движение', 'Водитель обязан занимать крайнюю правую полосу, кроме случаев обгона, объезда или поворота налево.'),

(8, 'Что обозначает знак "Главная дорога"?', '["Дорогу, на которой установлены светофоры", "Дорогу, по которой движение имеет преимущество перед пересекающими дорогами", "Дорогу с односторонним движением", "Дорогу с разрешённой высокой скоростью"]', 1, 'Дорожные знаки', 'Знак "Главная дорога" указывает на дорогу, водители которой имеют преимущество перед выезжающими с пересекающих дорог.'),

(9, 'В каком случае водитель обязан уступить дорогу пешеходу?', '["Только если пешеход уже пересекает проезжую часть", "Если пешеход уже ступил на нерегулируемый пешеходный переход или вступил на него", "Если пешеход стоит на краю тротуара", "Пешеход всегда обязан уступать дорогу транспорту"]', 1, 'Пешеходы', 'Водитель обязан уступить дорогу пешеходам, переходящим проезжую часть по нерегулируемому пешеходному переходу.'),

(10, 'Разрешается ли употребление алкоголя за рулём?', '["Допускается не более 0,5 промилле", "Запрещено полностью — нулевой уровень для всех водителей", "Допускается не более 0,2 промилле в выдыхаемом воздухе", "Разрешается слабоалкогольные напитки"]', 1, 'Ответственность', 'В России запрещено управление ТС в состоянии алкогольного опьянения. Допустимый уровень — 0,16 мг/л в выдыхаемом воздухе, но фактически это нулевая толерантность.'),

(11, 'Что означает прерывистая линия дорожной разметки посередине дороги?', '["Обгон запрещён", "Разделяет потоки попутного движения, разрешает перестроение", "Край проезжей части", "Полоса для движения общественного транспорта"]', 1, 'Разметка', 'Прерывистая линия в центре разделяет транспортные потоки противоположных направлений или попутного движения, разрешая перестроение.'),

(12, 'На каком расстоянии до населённого пункта устанавливается знак, информирующий о его начале?', '["50 м", "100 м", "150 м", "Непосредственно у начала застройки"]', 3, 'Дорожные знаки', 'Знак "Населённый пункт" устанавливается непосредственно у начала застройки и означает, что водитель въезжает в населённый пункт.'),

(13, 'Что обязан сделать водитель при приближении автомобиля скорой помощи с включёнными спецсигналами?', '["Остановиться немедленно", "Уступить дорогу, освободив крайнюю правую полосу или приняв вправо", "Продолжить движение", "Включить аварийную сигнализацию и остановиться"]', 1, 'Приоритет', 'Водители обязаны уступить дорогу транспортным средствам со специальными световыми и звуковыми сигналами.'),

(14, 'С какого расстояния в тёмное время суток должны быть видны задние габаритные огни транспортного средства?', '["100 м", "200 м", "300 м", "500 м"]', 2, 'Техническое состояние', 'Задние габаритные огни должны быть видны в тёмное время суток с расстояния не менее 300 метров.'),

(15, 'Каков минимальный возраст для управления легковым автомобилем категории B?', '["16 лет", "17 лет", "18 лет", "21 год"]', 2, 'Общие', 'Для управления транспортными средствами категории B минимальный возраст составляет 18 лет.'),

(16, 'Что означает знак "Уступите дорогу"?', '["Движение запрещено", "Водитель обязан уступить дорогу транспортным средствам, движущимся по пересекаемой дороге", "Главная дорога", "Остановка запрещена"]', 1, 'Дорожные знаки', 'Знак "Уступите дорогу" требует от водителя пропустить транспортные средства на пересекаемой дороге.'),

(17, 'На каком расстоянии до железнодорожного переезда без шлагбаума водитель обязан убедиться в отсутствии поезда?', '["Видимость должна быть не менее 50 м", "Должна быть обеспечена достаточная видимость переезда", "200 м", "Только непосредственно перед переездом"]', 1, 'Ж/Д переезды', 'Перед переездом без шлагбаума водитель обязан убедиться в отсутствии приближающегося поезда, руководствуясь зоной видимости.'),

(18, 'Что означает двойная сплошная линия разметки на дороге?', '["Рекомендуется держаться правее", "Запрещает пересечение и разделяет транспортные потоки противоположных направлений", "Разделяет полосы попутного движения", "Обозначает велосипедную дорожку"]', 1, 'Разметка', 'Двойная сплошная линия категорически запрещает пересечение и разделяет транспортные потоки противоположных направлений.'),

(19, 'Каков максимально допустимый уровень алкоголя в крови для водителя?', '["0,0 промилле (абсолютный ноль)", "0,2 промилле", "0,5 промилле", "1,0 промилле"]', 0, 'Ответственность', 'В России установлена нулевая норма алкоголя для водителей. Допустимый предел — 0,16 мг/л в выдыхаемом воздухе (погрешность прибора).'),

(20, 'В каком направлении разрешается выполнять разворот на перекрёстке?', '["Только налево", "Только направо", "С крайней левой полосы или специально обозначенной полосы", "В любом месте проезжей части"]', 2, 'Манёвры', 'Разворот выполняется с крайней левой полосы, если иное не предусмотрено знаками или разметкой.'),

(21, 'Что необходимо сделать водителю перед перестроением на другую полосу?', '["Ничего, если нет помех", "Включить световые указатели поворота и убедиться в безопасности манёвра", "Только посмотреть в зеркало", "Нажать на клаксон"]', 1, 'Манёвры', 'Перед перестроением водитель обязан включить сигнал поворота, убедиться в безопасности манёвра и не создавать помех другим участникам.'),

(22, 'Какое расстояние должен соблюдать водитель до впереди идущего транспортного средства?', '["10 метров", "20 метров", "Дистанцию, обеспечивающую безопасное торможение", "50 метров"]', 2, 'Движение', 'Водитель обязан соблюдать дистанцию до впереди движущегося транспортного средства, достаточную для безопасного торможения.'),

(23, 'Когда запрещено использование звукового сигнала в населённом пункте?', '["Никогда не запрещено", "Всегда, кроме предупреждения о грозящей опасности", "Только ночью", "Только в жилых зонах"]', 1, 'Движение', 'В населённых пунктах использование звукового сигнала запрещено, за исключением случаев предотвращения ДТП.'),

(24, 'Что должен сделать водитель, ставший участником ДТП с пострадавшими?', '["Продолжить движение", "Остановиться, включить аварийку, выставить знак аварийной остановки, вызвать экстренные службы, оказать первую помощь", "Только вызвать ГИБДД", "Самостоятельно отвезти пострадавших в больницу"]', 1, 'ДТП', 'При ДТП с пострадавшими водитель обязан: остановиться, включить аварийную сигнализацию, выставить знак аварийной остановки, вызвать экстренные службы и при необходимости оказать первую помощь.'),

(25, 'На каком расстоянии от перекрёстка запрещена стоянка?', '["5 м", "10 м", "15 м", "20 м"]', 0, 'Остановка и стоянка', 'Стоянка запрещена ближе 5 метров от пересечения проезжих частей.'),

(26, 'Что означает мигающий красный сигнал светофора?', '["Разрешает движение с осторожностью", "Запрещает движение и информирует об опасном пересечении", "Требует снизить скорость", "Обозначает конец зоны ограничения скорости"]', 1, 'Светофоры', 'Мигающий красный сигнал запрещает движение и предупреждает об особой опасности (например, у ж/д переезда).'),

(27, 'Кому обязан уступить дорогу водитель, выезжающий с грунтовой дороги на дорогу без знаков приоритета?', '["Никому", "Транспортным средствам, движущимся по дороге с твёрдым покрытием", "Только пешеходам", "Только автобусам и трамваям"]', 1, 'Приоритет', 'При выезде с грунтовой дороги на дорогу с твёрдым покрытием водитель обязан уступить дорогу транспортным средствам, движущимся по этой дороге.'),

(28, 'Обязательно ли использование ремней безопасности?', '["Только для водителя", "Только на загородных трассах", "Для водителя и всех пассажиров", "Только для пассажиров на задних сиденьях"]', 2, 'Безопасность', 'Водитель и все пассажиры обязаны пристёгиваться ремнями безопасности при движении.'),

(29, 'Какой знак запрещает остановку транспортных средств?', '["Красный круг с горизонтальной полосой", "Синий круг со стрелкой", "Красный круг с буквой А", "Жёлтый треугольник"]', 0, 'Дорожные знаки', 'Знак "Остановка запрещена" — красный круг с горизонтальной красной полосой — запрещает остановку и стоянку.'),

(30, 'На какое расстояние разрешается буксировка неисправного автомобиля на гибкой сцепке?', '["Не ограничено", "Не более 50 км", "Допустима, но со скоростью не более 50 км/ч и с включёнными аварийными огнями", "Не разрешается"]', 2, 'Движение', 'Буксировка на гибкой сцепке разрешена со скоростью не более 50 км/ч с обязательным использованием аварийной сигнализации.'),

(31, 'Где разрешена стоянка транспортных средств?', '["На любом участке дороги", "Только на специально обозначенных местах или там, где это не запрещено знаками и разметкой", "На тротуаре при необходимости", "Только за пределами населённых пунктов"]', 1, 'Остановка и стоянка', 'Стоянка разрешена в местах, не запрещённых знаками и разметкой, без создания помех другим участникам движения.'),

(32, 'Какова максимальная скорость для транспортных средств с прицепом на автомагистрали?', '["90 км/ч", "100 км/ч", "110 км/ч", "130 км/ч"]', 0, 'Скоростной режим', 'Транспортные средства с прицепом на автомагистрали не должны превышать скорость 90 км/ч.'),

(33, 'Когда запрещён обгон?', '["На прямых участках дороги", "На перекрёстках, пешеходных переходах, в туннелях, на подъёмах, на поворотах с ограниченной видимостью", "При хорошей видимости", "Только в ночное время"]', 1, 'Обгон', 'Обгон запрещён в местах с ограниченной видимостью и на опасных участках: перекрёстки, пешеходные переходы, тоннели, подъёмы, повороты.'),

(34, 'Что означает знак "Пешеходный переход"?', '["Место, где пешеходы обязаны уступать транспорту", "Обозначает место, где пешеходы имеют приоритет для пересечения проезжей части", "Зона, где пешеходам запрещено движение", "Место остановки автобуса"]', 1, 'Дорожные знаки', 'Знак "Пешеходный переход" обозначает место, специально отведённое для перехода проезжей части пешеходами.'),

(35, 'Допускается ли движение задним ходом на перекрёстке?', '["Да, при наличии достаточного пространства", "Нет, на перекрёстках движение задним ходом запрещено", "Да, но только при медленной скорости", "Да, если нет других участников движения"]', 1, 'Манёвры', 'Движение задним ходом на перекрёстках и в других опасных местах запрещено Правилами дорожного движения.'),

(36, 'Какой документ водитель обязан иметь при себе?', '["Только паспорт", "Водительское удостоверение, документы на ТС (СТС) и полис ОСАГО", "Только водительское удостоверение", "Технический паспорт автомобиля"]', 1, 'Документы', 'Водитель обязан иметь при себе: водительское удостоверение, свидетельство о регистрации ТС и полис ОСАГО.'),

(37, 'Как следует вести себя водителю при приближении к нерегулируемому железнодорожному переезду?', '["Проехать не останавливаясь", "Снизить скорость, при необходимости остановиться, убедиться в отсутствии поезда", "Включить дальний свет", "Дать звуковой сигнал"]', 1, 'Ж/Д переезды', 'Перед нерегулируемым ж/д переездом водитель обязан снизить скорость, при необходимости остановиться и убедиться в отсутствии приближающегося поезда.'),

(38, 'При какой минимальной скорости разрешается движение по автомагистрали?', '["40 км/ч", "50 км/ч", "60 км/ч", "Нет ограничения по минимальной скорости"]', 2, 'Скоростной режим', 'На автомагистрали запрещено движение со скоростью менее 40 км/ч. Допустимый минимум — 40 км/ч.'),

(39, 'Что должен сделать водитель перед началом движения задним ходом?', '["Просто посмотреть в зеркала", "Убедиться в безопасности манёвра и при необходимости воспользоваться помощью других лиц", "Дать звуковой сигнал", "Включить правый поворотник"]', 1, 'Манёвры', 'Перед движением задним ходом водитель обязан убедиться в безопасности манёвра и при необходимости воспользоваться помощью других лиц.'),

(40, 'Что означает жёлтый мигающий сигнал светофора?', '["Разрешает движение с повышенной скоростью", "Движение разрешено, водитель должен быть внимателен и соблюдать осторожность", "Движение запрещено", "Требует полной остановки"]', 1, 'Светофоры', 'Жёлтый мигающий сигнал информирует о нерегулируемом перекрёстке или пешеходном переходе и требует особой осторожности.');
